operations.reducer:
const signerUser = action.context?.signer?.user;
const userAddr = signerUser?.address ? signerUser.address.toLowerCase() : null;
const inputAddr = action.input.address.toLowerCase();
if (state.owner) {
  if (!userAddr || userAddr !== state.owner) {
    throw new NotOwnerError("Only the current owner can transfer ownership");
  }
} else if (userAddr && userAddr !== inputAddr) {
  throw new SelfClaimRequiredError("A user-signed claim must set the signer's own address as owner");
}
state.owner = inputAddr;

if (action.input.label) {
  state.label = action.input.label;
  state.status = "CHANGES_PENDING";
}

if (action.input.genericSubdomain) {
  state.genericSubdomain = action.input.genericSubdomain;
  state.status = "CHANGES_PENDING";
}

state.customDomain = {
  enabled: action.input.enabled,
  domain: action.input.domain || null,
  dnsRecords: state.customDomain.dnsRecords || [],
};
state.status = "CHANGES_PENDING";

operations.schema:
input SetCustomDomainInput {
  enabled: Boolean!
  domain: String
}

operations.reducer:
state.customDomain.dnsRecords = action.input.records.map((r) => ({
  type: r.type,
  host: r.host,
  value: r.value,
}));

operations.schema:
input SetDnsRecordsInput {
  records: [DnsRecordInput!]!
}

input DnsRecordInput {
  type: String!
  host: String!
  value: String!
}

operations.reducer:
const type = action.input.type ?? null;
if (type) {
  const svc = state.services.find((s) => s.type === type);
  if (!svc || !svc.enabled) {
    throw new ServiceNotEnabledError(type + " is not enabled — enable it before pinning to apex");
  }
}
state.apexService = type;
if (state.status === "READY" || state.status === "DEPLOYING") {
  state.status = "CHANGES_PENDING";
} else if (state.status !== "DRAFT") {
  state.status = "CHANGES_PENDING";
}

const { type, prefix, clintConfig } = action.input;
if (type === "CLINT" && !clintConfig) {
  throw new ClintConfigRequiredError("clintConfig is required when enabling a CLINT service");
}
if (!state.services) {
  state.services = [];
}
const other = state.services.find((s) => s.prefix === prefix && s.type !== type);
if (other) {
  throw new PrefixInUseError(`prefix '${prefix}' is already in use by service ${other.type}`);
}
const config = type === "CLINT" && clintConfig ? {
  package: clintConfig.package,
  env: clintConfig.env ?? [],
  serviceCommand: clintConfig.serviceCommand ?? null,
  selectedRessource: clintConfig.selectedRessource ?? null,
} : null;
const existing = state.services.find((s) => s.type === type && s.prefix === prefix);
if (existing) {
  existing.enabled = true;
  existing.prefix = prefix;
  if (config) existing.config = config;
} else {
  state.services.push({ type, prefix, enabled: true, url: null, status: "PROVISIONING", version: null, config, selectedRessource: action.input.selectedRessource ?? "VETRA_AGENT_S" });
}
state.status = "CHANGES_PENDING";

operations.schema:
input EnableServiceInput {
  type: VetraCloudEnvironmentServiceType!
  prefix: String!
  clintConfig: VetraCloudServiceClintInput
  selectedRessource: VetraCloudRessourceSize
}

input VetraCloudServiceClintInput {
  package: VetraCloudPackageInput!
  env: [VetraCloudServiceEnvInput!]!
  serviceCommand: String
  selectedRessource: VetraCloudRessourceSize
}

input VetraCloudPackageInput {
  registry: URL!
  name: String!
  version: String
}

input VetraCloudServiceEnvInput {
  name: String!
  value: String
  isSecret: Boolean
}

operations.reducer:
const { prefix, config } = action.input;
if (!state.services) {
  state.services = [];
}
const service = state.services.find((s) => s.prefix === prefix);
if (!service) {
  throw new ServiceNotFoundError(`No service with prefix '${prefix}'`);
}
if (service.type !== "CLINT") {
  throw new NotClintServiceError(`Service '${prefix}' is type ${service.type}; only CLINT services accept config`);
}
service.config = {
  package: config.package,
  env: config.env ?? [],
  serviceCommand: config.serviceCommand ?? null,
  selectedRessource: config.selectedRessource ?? null,
};
if (config.selectedRessource) {
  service.selectedRessource = config.selectedRessource;
}
state.status = "CHANGES_PENDING";

operations.schema:
input SetServiceConfigInput {
  prefix: String!
  config: VetraCloudServiceClintConfigInput!
}

input VetraCloudServiceClintConfigInput {
  package: VetraCloudPackageConfigInput!
  env: [VetraCloudServiceEnvConfigInput!]!
  serviceCommand: String
  selectedRessource: VetraCloudRessourceSize
}

input VetraCloudPackageConfigInput {
