  name: String!
  version: String
}

input VetraCloudServiceEnvConfigInput {
  name: String!
  value: String
  isSecret: Boolean
}

operations.reducer:
const { type } = action.input;
if (!state.services) {
  state.services = [];
}
const service = state.services.find((s) => s.type === type);
if (service) {
  service.enabled = false;
  state.status = "CHANGES_PENDING";
}

operations.schema:
input DisableServiceInput {
  type: VetraCloudEnvironmentServiceType!
  prefix: String
}

operations.reducer:
const service = state.services.find((s) => s.type === action.input.type);
if (!service) {
  throw new ServiceNotFoundError("Service " + action.input.type + " not found");
}
service.enabled = !service.enabled;
state.status = "CHANGES_PENDING";

const service = state.services.find((s) => s.type === action.input.type);
if (!service) {
  throw new ServiceNotFoundError("Service " + action.input.type + " not found");
}
service.prefix = action.input.prefix;
state.status = "CHANGES_PENDING";

operations.schema:
input UpdateServicePrefixInput {
  type: VetraCloudEnvironmentServiceType!
  prefix: String!
}

operations.reducer:
const service = state.services.find((s) => s.type === action.input.type);
if (!service) {
  throw new ServiceNotFoundError("Service " + action.input.type + " not found");
}
service.status = action.input.status;
if (action.input.url) {
  service.url = action.input.url;
}

operations.schema:
input SetServiceStatusInput {
  type: VetraCloudEnvironmentServiceType!
  status: ServiceStatus!
  url: String
}

operations.reducer:
const service = state.services.find((s) => s.type === action.input.type);
if (!service) {
  throw new ServiceNotFoundError("Service " + action.input.type + " not found");
}
service.version = action.input.version;
markPendingIfDeployed(state);

operations.schema:
input SetServiceVersionInput {
  type: VetraCloudEnvironmentServiceType!
  version: String!
}

operations.reducer:
const service = state.services?.find((s) => s.prefix === action.input.prefix);
if (!service) {
  throw new ServiceNotFoundError(`No service with prefix '${action.input.prefix}'`);
}
service.selectedRessource = action.input.size;
if (service.type === "CLINT" && service.config) {
  service.config.selectedRessource = action.input.size;
}
state.status = "CHANGES_PENDING";

operations.schema:
input SetServiceSizeInput {
  prefix: String!
  size: VetraCloudRessourceSize!
}

operations.reducer:
const { packageName, version, registry } = action.input;
if (!state.packages) {
  state.packages = [];
}
const resolvedVersion = version ?? "latest";
const resolvedRegistry = registry || state.defaultPackageRegistry || "";
const existing = state.packages.find((p) => p.name === packageName);
if (existing) {
  existing.version = resolvedVersion;
  if (registry) existing.registry = resolvedRegistry;
} else {
  state.packages.push({ registry: resolvedRegistry, name: packageName, version: resolvedVersion });
}
state.status = "CHANGES_PENDING";

operations.schema:
input AddPackageInput {
  registry: URL
  packageName: String!
  version: String
}

operations.reducer:
const { packageName } = action.input;
if (!state.packages) {
  state.packages = [];
}
if (packageName) {
  state.packages = state.packages.filter((p) => p.name !== packageName);
  state.status = "CHANGES_PENDING";
}

const pkg = state.packages.find((p) => p.name === action.input.packageName);
if (!pkg) {
  throw new PackageNotFoundError("Package " + action.input.packageName + " not found");
}
pkg.version = action.input.version;
markPendingIfDeployed(state);

operations.schema:
input SetPackageVersionInput {
  packageName: String!
  version: String!
}

operations.reducer:
if (state.status !== "DRAFT") {
  throw new InvalidStatusTransitionError("INITIALIZE can only be called from DRAFT status, current: " + state.status);
}
state.genericSubdomain = action.input.genericSubdomain;
state.genericBaseDomain = action.input.genericBaseDomain;
state.defaultPackageRegistry = action.input.defaultPackageRegistry || null;
state.status = "CHANGES_APPROVED";

operations.schema:
input InitializeInput {
  genericSubdomain: String!
  genericBaseDomain: String!
  defaultPackageRegistry: URL
}

operations.reducer:
if (state.status !== "CHANGES_APPROVED") {
  throw new InvalidStatusTransitionError("MARK_CHANGES_PUSHED can only be called from CHANGES_APPROVED status, current: " + state.status);
}
state.status = "CHANGES_PUSHED";

if (state.status !== "CHANGES_PUSHED") {
  throw new InvalidStatusTransitionError("MARK_DEPLOYMENT_STARTED can only be called from CHANGES_PUSHED status, current: " + state.status);
}
state.status = "DEPLOYING";

if (state.status !== "DEPLOYING") {
  throw new InvalidStatusTransitionError("REPORT_DEPLOYMENT_SUCCEEDED can only be called from DEPLOYING status, current: " + state.status);
}
state.status = "READY";

if (state.status !== "DEPLOYING") {
  throw new InvalidStatusTransitionError("REPORT_DEPLOYMENT_FAILED can only be called from DEPLOYING status, current: " + state.status);
}
state.status = "DEPLOYMENt_FAILED";

operations.schema:
input ReportDeploymentFailedInput {
  code: String!
  message: String!
}

operations.reducer:
if (state.status !== "CHANGES_PENDING") {
  throw new InvalidStatusTransitionError("APPROVE_CHANGES can only be called from CHANGES_PENDING status, current: " + state.status);
}
state.status = "CHANGES_APPROVED";

if (state.status !== "TERMINATING") {
  throw new InvalidStatusTransitionError("MARK_DESTROYED can only be called from TERMINATING status, current: " + state.status);
}
state.status = "DESTROYED";

if (state.status !== "DESTROYED") {
  throw new InvalidStatusTransitionError("ARCHIVE can only be called from DESTROYED status, current: " + state.status);
}
state.status = "ARCHIVED";

if (state.status !== "ARCHIVED") {
  throw new InvalidStatusTransitionError("UNARCHIVE can only be called from ARCHIVED status, current: " + state.status);
}
state.status = "DESTROYED";
